import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        long first = 1;
        long second = 1;

        for (int i = 2; i <= n; i++) {
            long next = first + second;
            first = second;
            second = next;
        }

        System.out.println(second);
    }
}
